# Math utilities module providing calculation tools

class Calculator:
    total: int

    def __init__(self):
        self.total = 0

    def add(self, a: int, b: int) -> int:
        return a + b

    def multiply(self, a: int, b: int) -> int:
        return a * b

def format_number(n: int) -> str:
    return f"Value: {n}"

